INSERT INTO TWORK_INTF_DLVRYCORP_RCV
(
    CTKEY            /* 센터코드 */
  , OWKEY            /* 화주코드 */
  , DLVRYCORPCD      /* 택배사코드 */
  , DLVRYCORPNM      /* 택배사명 */
  , CNTRCTCD         /* 계약코드 */
  , CNTRCTNO         /* 계약번호 */
