/* wms-master-dlvry-sql-oracle.xml - updateDlvryMst - 택배사 마스터 정보 Update */
UPDATE TWORK_MST_DLVRYCORP
   SET DLVRYCORPNM     = #{dlvrycorpnm}     /* 택배사명 */
     , CNTRCTCD        = #{cntrctcd}        /* 계약코드 */
     , CNTRCTNO        = #{cntrctno}        /* 계약번호 */
     , CNTRCTSTATUS    = #{cntrctstatus}    /* 계약상태 */
     , CNTRCTSTARTDAY  = #{cntrctstartday}  /* 계약시작일 */
     , CNTRCTCLOSEDAY  = #{cntrctcloseday}  /* 계약종료일 */
     , TSDNOTIRT       = #{tsdnotirt}       /* 임계치알림율 */
     , DELYN           = CASE WHEN #{cntrctstatus} = '2' THEN 'Y'
                              ELSE #{delyn}
                         END   /* 삭제여부 */
     , UPDATEDATE      = #{sysdate}         /* 수정일시 */
     , UPDATEURKEY     = #{surkey}          /* 수정자 */
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND DLVRYCORPCD = #{dlvrycorpcd}
AND CNTRCTCD = #{cntrctcd}

